#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(long long*)a - *(long long*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        long long A[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        qsort(A, N, sizeof(long long), compare);
        int cut = 0;
        int bouquet = 0;
        long long curr_len = 0;
        for (int i = 0; i < N; i++) {
            if (curr_len == 0) {
                curr_len = A[i];
                bouquet++;
            } else if (curr_len != A[i]) {
                cut++;
                curr_len = A[i];
                bouquet++;
            }
            if (bouquet == K) {
                bouquet = 0;
                curr_len = 0;
            }
        }
        printf("%d\n", cut);
    }
    return 0;
}

