import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            long[] A = new long[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextLong();
            }
            Arrays.sort(A);
            int cut = 0;
            int bouquet = 0;
            long curr_len = 0;
            for (int i = N - 1; i >= 0; i--) {
                if (curr_len == 0) {
                    curr_len = A[i];
                    bouquet++;
                } else if (curr_len != A[i]) {
                    cut++;
                    curr_len = A[i];
                    bouquet++;
                }
                if (bouquet == K) {
                    bouquet = 0;
                    curr_len = 0;
                }
            }
            System.out.println(cut);
        }
    }
}

